/**
 * Giga connectivity status taxonomy.
 *
 * Single source of truth for the connectivity states used across Giga Maps:
 * status values, human labels, descriptions and the brand colours (from the
 * Giga style guide). Components read colours from here as inline styles so the
 * kit renders correctly even before a consumer extends their Tailwind config.
 */

export type ConnectivityStatus = "good" | "moderate" | "bad" | "unmapped";

export interface ConnectivityMeta {
  value: ConnectivityStatus;
  /** Short label for legends and chips. */
  label: string;
  /** Longer description for tooltips / legends. */
  description: string;
  /** Brand hex from the Giga style guide. */
  hex: string;
}

export const CONNECTIVITY: Record<ConnectivityStatus, ConnectivityMeta> = {
  good: {
    value: "good",
    label: "Good",
    description: "Connected with good download speed",
    hex: "#00d661",
  },
  moderate: {
    value: "moderate",
    label: "Moderate",
    description: "Connected with slow download speed",
    hex: "#ffc93d",
  },
  bad: {
    value: "bad",
    label: "No connectivity",
    description: "Mapped, but no connectivity",
    hex: "#ed1c24",
  },
  unmapped: {
    value: "unmapped",
    label: "Unmapped",
    description: "No location or connectivity data",
    hex: "#989898",
  },
};

/** Canonical display order: best → worst → unknown. */
export const CONNECTIVITY_ORDER: ConnectivityStatus[] = [
  "good",
  "moderate",
  "bad",
  "unmapped",
];

export function connectivityHex(status: ConnectivityStatus): string {
  return CONNECTIVITY[status].hex;
}

"use client";

import * as React from "react";
import { cn } from "@/lib/utils";
import {
  CONNECTIVITY,
  type ConnectivityStatus,
} from "@/components/giga/lib/connectivity";

const sizeMap = { sm: 10, md: 14, lg: 18 } as const;

export interface StatusMarkerProps
  extends React.HTMLAttributes<HTMLSpanElement> {
  status: ConnectivityStatus;
  size?: keyof typeof sizeMap;
  /** When > 1, renders a counted cluster bubble instead of a single dot. */
  count?: number;
  /** Animated ping to draw attention (single markers only). */
  pulse?: boolean;
  /** Selected state — emphasised ring. */
  selected?: boolean;
}

/**
 * Connectivity status marker — a coloured dot (or counted cluster) for plotting
 * Giga entities on a map. Presentational and map-engine agnostic: the consumer
 * positions it (absolute / overlay) on whatever map library they use.
 */
export function StatusMarker({
  status,
  size = "md",
  count,
  pulse,
  selected,
  className,
  style,
  ...props
}: StatusMarkerProps) {
  const meta = CONNECTIVITY[status];
  const px = sizeMap[size];
  const isCluster = typeof count === "number" && count > 1;
  const dimension = isCluster ? px + 12 : px;

  return (
    <span
      role="img"
      aria-label={
        isCluster ? `${count} entities — ${meta.label}` : meta.label
      }
      className={cn(
        "relative inline-flex items-center justify-center rounded-full ring-2 ring-background transition-transform",
        selected && "z-10 scale-110 ring-foreground",
        className,
      )}
      style={{
        backgroundColor: meta.hex,
        width: dimension,
        height: dimension,
        ...style,
      }}
      {...props}
    >
      {isCluster && (
        <span className="px-1 text-[10px] font-semibold leading-none text-black/80">
          {count > 99 ? "99+" : count}
        </span>
      )}
      {pulse && !isCluster && (
        <span
          aria-hidden
          className="absolute inset-0 animate-ping rounded-full"
          style={{ backgroundColor: meta.hex, opacity: 0.5 }}
        />
      )}
    </span>
  );
}

"use client";

import * as React from "react";
import { cn } from "@/lib/utils";
import {
  CONNECTIVITY,
  CONNECTIVITY_ORDER,
  type ConnectivityStatus,
} from "@/components/giga/lib/connectivity";

export interface ConnectivityLegendProps
  extends React.HTMLAttributes<HTMLDivElement> {
  title?: string;
  /** Optional counts shown next to each status. */
  counts?: Partial<Record<ConnectivityStatus, number>>;
  /** Which statuses to show, in order. Defaults to all. */
  statuses?: ConnectivityStatus[];
  orientation?: "vertical" | "horizontal";
}

/**
 * Connectivity legend — the map key that explains the status colours. Floats
 * over the map (typically bottom-right). Pair with `StatusMarker`.
 */
export function ConnectivityLegend({
  title = "Connectivity",
  counts,
  statuses = CONNECTIVITY_ORDER,
  orientation = "vertical",
  className,
  ...props
}: ConnectivityLegendProps) {
  return (
    <div
      className={cn(
        "rounded-md border bg-card/95 p-3 text-card-foreground shadow-lg backdrop-blur",
        className,
      )}
      {...props}
    >
      {title && (
        <p className="mb-2 text-xs font-semibold text-muted-foreground">
          {title}
        </p>
      )}
      <ul
        className={cn(
          "flex gap-x-4 gap-y-2",
          orientation === "vertical"
            ? "flex-col"
            : "flex-row flex-wrap items-center",
        )}
      >
        {statuses.map((s) => {
          const meta = CONNECTIVITY[s];
          const count = counts?.[s];
          return (
            <li key={s} className="flex items-center gap-2 text-sm">
              <span
                aria-hidden
                className="size-2.5 shrink-0 rounded-full"
                style={{ backgroundColor: meta.hex }}
              />
              <span className="text-foreground">{meta.label}</span>
              {count != null && (
                <span className="ml-auto pl-3 tabular-nums text-muted-foreground">
                  {count.toLocaleString()}
                </span>
              )}
            </li>
          );
        })}
      </ul>
    </div>
  );
}

"use client";

import * as React from "react";
import { cn } from "@/lib/utils";

export interface EntityType {
  value: string;
  label: string;
  icon?: React.ReactNode;
}

export const DEFAULT_ENTITY_TYPES: EntityType[] = [
  { value: "all", label: "All entities" },
  { value: "schools", label: "Schools" },
  { value: "health", label: "Health centers" },
];

type SingleProps = {
  multiple?: false;
  value: string;
  onValueChange?: (value: string) => void;
};

type MultiProps = {
  multiple: true;
  value: string[];
  onValueChange?: (value: string[]) => void;
};

export type EntityTypeSelectorProps = {
  types?: EntityType[];
  className?: string;
} & (SingleProps | MultiProps);

/**
 * Entity-type selector — the pill segmented control that filters the map by
 * entity type (All / Schools / Health centers). Supports single-select
 * (`radiogroup`) and multi-select (`group` of checkboxes).
 */
export function EntityTypeSelector(props: EntityTypeSelectorProps) {
  const { types = DEFAULT_ENTITY_TYPES, className } = props;

  const isActive = (value: string) =>
    props.multiple ? props.value.includes(value) : props.value === value;

  const toggle = (value: string) => {
    if (props.multiple) {
      const next = new Set(props.value);
      if (next.has(value)) {
        next.delete(value);
      } else {
        next.add(value);
      }
      props.onValueChange?.(Array.from(next));
    } else {
      props.onValueChange?.(value);
    }
  };

  return (
    <div
      role={props.multiple ? "group" : "radiogroup"}
      className={cn(
        "inline-flex items-center gap-1 rounded-full border bg-card p-1 shadow-sm",
        className,
      )}
    >
      {types.map((type) => {
        const active = isActive(type.value);
        return (
          <button
            key={type.value}
            type="button"
            role={props.multiple ? "checkbox" : "radio"}
            aria-checked={active}
            onClick={() => toggle(type.value)}
            className={cn(
              "inline-flex items-center gap-1.5 rounded-full px-3 py-1.5 text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
              active
                ? "bg-primary text-primary-foreground shadow-sm"
                : "text-muted-foreground hover:bg-muted hover:text-foreground",
            )}
          >
            {type.icon}
            {type.label}
          </button>
        );
      })}
    </div>
  );
}

import * as React from "react";
import { cn } from "@/lib/utils";
import { Card } from "@/components/ui/card";
import { CONNECTIVITY } from "@/components/giga/lib/connectivity";

export interface StatTileProps extends React.HTMLAttributes<HTMLDivElement> {
  label: string;
  value: React.ReactNode;
  unit?: string;
  /** Trend indicator. */
  delta?: { value: string; direction: "up" | "down" | "flat" };
  icon?: React.ReactNode;
  /** Slot for a sparkline / mini chart (e.g. Recharts). */
  chart?: React.ReactNode;
}

/**
 * Stat tile — a compact KPI card used throughout the Giga Maps detail panel
 * (schools mapped, % with connectivity, etc.). Optional trend and chart slot.
 */
export function StatTile({
  label,
  value,
  unit,
  delta,
  icon,
  chart,
  className,
  ...props
}: StatTileProps) {
  return (
    <Card className={cn("p-4", className)} {...props}>
      <div className="flex items-start justify-between gap-2">
        <p className="text-sm text-muted-foreground">{label}</p>
        {icon && <span className="text-muted-foreground">{icon}</span>}
      </div>
      <div className="mt-1 flex items-baseline gap-1">
        <span className="font-heading text-2xl text-foreground">{value}</span>
        {unit && <span className="text-sm text-muted-foreground">{unit}</span>}
      </div>
      {delta && (
        <p
          className={cn(
            "mt-1 text-xs",
            delta.direction === "down" && "text-destructive",
            delta.direction === "flat" && "text-muted-foreground",
          )}
          style={
            delta.direction === "up"
              ? { color: CONNECTIVITY.good.hex }
              : undefined
          }
        >
          {delta.value}
        </p>
      )}
      {chart && <div className="mt-3">{chart}</div>}
    </Card>
  );
}

"use client";

import * as React from "react";
import { ChevronLeft, ChevronRight, X } from "lucide-react";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import { ScrollArea } from "@/components/ui/scroll-area";

export interface MapDetailPanelProps
  extends React.HTMLAttributes<HTMLDivElement> {
  title: string;
  subtitle?: string;
  collapsed?: boolean;
  onCollapsedChange?: (collapsed: boolean) => void;
  onClose?: () => void;
  side?: "left" | "right";
  footer?: React.ReactNode;
}

/**
 * Map detail panel — the collapsible side panel that holds entity stats,
 * filters and details over the map. Header carries a collapse toggle and an
 * optional close. Content scrolls; an optional sticky footer holds CTAs.
 */
export function MapDetailPanel({
  title,
  subtitle,
  collapsed = false,
  onCollapsedChange,
  onClose,
  side = "left",
  footer,
  className,
  children,
  ...props
}: MapDetailPanelProps) {
  const Chevron =
    side === "left"
      ? collapsed
        ? ChevronRight
        : ChevronLeft
      : collapsed
        ? ChevronLeft
        : ChevronRight;

  return (
    <div
      className={cn(
        "flex h-full flex-col overflow-hidden rounded-lg border bg-card text-card-foreground shadow-md transition-[width] duration-300",
        collapsed ? "w-14" : "w-80",
        className,
      )}
      {...props}
    >
      <div className="flex items-center gap-2 border-b p-3">
        {onCollapsedChange && (
          <Button
            variant="ghost"
            size="icon"
            className="size-7 shrink-0"
            aria-label={collapsed ? "Expand panel" : "Collapse panel"}
            onClick={() => onCollapsedChange(!collapsed)}
          >
            <Chevron className="size-4" />
          </Button>
        )}
        {!collapsed && (
          <div className="min-w-0 flex-1">
            <p className="truncate font-heading text-base font-medium leading-tight">
              {title}
            </p>
            {subtitle && (
              <p className="truncate text-xs text-muted-foreground">
                {subtitle}
              </p>
            )}
          </div>
        )}
        {!collapsed && onClose && (
          <Button
            variant="ghost"
            size="icon"
            className="size-7 shrink-0"
            aria-label="Close"
            onClick={onClose}
          >
            <X className="size-4" />
          </Button>
        )}
      </div>

      {!collapsed && (
        <>
          <ScrollArea className="flex-1">
            <div className="space-y-4 p-3">{children}</div>
          </ScrollArea>
          {footer && <div className="border-t p-3">{footer}</div>}
        </>
      )}
    </div>
  );
}

import * as React from "react";
import { cn } from "@/lib/utils";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { StatusMarker } from "@/components/giga/status-marker";
import {
  CONNECTIVITY,
  type ConnectivityStatus,
} from "@/components/giga/lib/connectivity";

export interface EntityStat {
  label: string;
  value: React.ReactNode;
}

export interface MapEntityPopupProps
  extends React.HTMLAttributes<HTMLDivElement> {
  name: string;
  /** e.g. "School" | "Health center". */
  entityType?: string;
  status: ConnectivityStatus;
  location?: string;
  stats?: EntityStat[];
  onViewDetails?: () => void;
}

/**
 * Map entity popup — the card shown when an entity (school / health center) is
 * selected on the map. Leads with the connectivity status, then key stats and
 * a "View details" action that opens the full detail panel.
 */
export function MapEntityPopup({
  name,
  entityType = "School",
  status,
  location,
  stats = [],
  onViewDetails,
  className,
  ...props
}: MapEntityPopupProps) {
  const meta = CONNECTIVITY[status];

  return (
    <Card className={cn("w-72 overflow-hidden p-0 shadow-lg", className)} {...props}>
      <div className="flex items-start gap-3 p-3">
        <StatusMarker status={status} size="lg" className="mt-0.5" />
        <div className="min-w-0 flex-1">
          <p className="truncate font-heading text-base font-medium leading-tight">
            {name}
          </p>
          <p className="truncate text-xs text-muted-foreground">
            {entityType}
            {location ? ` · ${location}` : ""}
          </p>
          <p className="mt-1 text-xs font-medium" style={{ color: meta.hex }}>
            {meta.label}
          </p>
        </div>
      </div>

      {stats.length > 0 && (
        <div className="grid grid-cols-2 gap-px bg-border">
          {stats.map((stat, i) => (
            <div key={i} className="bg-card p-3">
              <p className="text-xs text-muted-foreground">{stat.label}</p>
              <p className="font-heading text-sm text-foreground">
                {stat.value}
              </p>
            </div>
          ))}
        </div>
      )}

      {onViewDetails && (
        <div className="p-3 pt-2">
          <Button className="w-full" onClick={onViewDetails}>
            View details
          </Button>
        </div>
      )}
    </Card>
  );
}
